from flask import Flask, request, redirect, session, url_for
import os
import requests
import urllib.parse

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'fallback-secret-key')

# Configuration
CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID')
CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET')
AUTHORIZATION_BASE_URL = os.environ.get('AUTHORIZATION_BASE_URL')
TOKEN_URL = os.environ.get('TOKEN_URL')
REDIRECT_URI = os.environ.get('REDIRECT_URI')
ALLOWED_DOMAIN = os.environ.get('ALLOWED_DOMAIN')

@app.route('/')
def index():
    return '<a href="/login">Login with OAuth</a>'

@app.route('/login')
def login():
    if not REDIRECT_URI or not ALLOWED_DOMAIN:
        return 'Configuration error: REDIRECT_URI or ALLOWED_DOMAIN not set', 500
    
    # Validate redirect URI domain
    if ALLOWED_DOMAIN not in REDIRECT_URI:
        return 'Invalid redirect URI domain', 400
    
    # Generate state parameter for security
    state = os.urandom(24).hex()
    session['oauth_state'] = state
    
    # Build authorization URL
    authorization_url = (
        f"{AUTHORIZATION_BASE_URL}?"
        f"response_type=code&"
        f"client_id={CLIENT_ID}&"
        f"redirect_uri={urllib.parse.quote(REDIRECT_URI, safe='')} &"
        f"state={state}&"
        f"scope=openid profile email"
    )
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    # Validate state parameter
    if request.args.get('state') != session.get('oauth_state'):
        return 'Invalid state parameter', 400
    
    # Get authorization code
    code = request.args.get('code')
    if not code:
        return 'Authorization code not received', 400
    
    # Exchange code for token
    token_response = requests.post(
        TOKEN_URL,
        data={
            'grant_type': 'authorization_code',
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET,
            'code': code,
            'redirect_uri': REDIRECT_URI
        }
    )
    
    if token_response.status_code != 200:
        return 'Token exchange failed', 400
    
    token_data = token_response.json()
    
    # Store token in session or database
    session['oauth_token'] = token_data
    
    return 'Login successful!'

if __name__ == '__main__':
    app.run(debug=True)